#include <iostream>
#include <vector>

using namespace std;

void doubleInPlace(vector<int> &numbers)
{
    for (int i = 0; i < numbers.size(); i++)
    {
        numbers[i] = numbers[i] * 2; // modify directly, no new array
    }
}

int main()
{
    vector<int> numbers = {1, 2, 3};

    doubleInPlace(numbers);

    for (int n : numbers)
    {
        cout << n << " ";
    }

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

int findMax(vector<int> &numbers)
{
    int maxVal = numbers[0];
    for (int i = 1; i < numbers.size(); i++)
    {
        if (numbers[i] > maxVal)
        {
            maxVal = numbers[i];
        }
    }
    return maxVal;
}

int main()
{
    vector<int> numbers = {4, 9, 2, 7};

    cout << findMax(numbers) << endl;

    return 0;
}

